class Solution {
    public int isPrefixOfWord(String sentence, String searchWord) {
        int[] wordIndexes = new int[searchWord.length()];
        int index = getWordIndexes(sentence, searchWord, 0, wordIndexes);
        return index >= 0 ? wordIndexes[index] : -1;
    }

    private int getWordIndexes(String sentence, String searchWord, int startIndex, int[] wordIndexes) {
        for (int i = startIndex; i < sentence.length(); i++) {
            if (isPrefix(sentence.substring(startIndex, i + 1), searchWord)) {
                wordIndexes[i - startIndex] = i;
            }
        }
        return findMinIndex(wordIndexes);
    }

    private boolean isPrefix(String s1, String s2) {
        for (int i = 0; i < s1.length(); i++) {
            if (s1.charAt(i) != s2.charAt(i)) {
                return false;
            }
        }
        return true;
    }

    private int findMinIndex(int[] wordIndexes) {
        int minIndex = wordIndexes[0];
        for (int i = 1; i < wordIndexes.length; i++) {
            if (wordIndexes[i] < minIndex) {
                minIndex = wordIndexes[i];
            }
        }
        return minIndex;
    }
}
